    // ops[] in DX7 SysEx: index 0 = Op6 (deepest modulator), index 5 = Op1 (output carrier)
    // Primary pair: Op1 (ops[5]) as carrier, Op2 (ops[4]) as direct modulator.
    // Secondary pair: Op3 (ops[3]) as second carrier, Op4 (ops[2]) as its modulator —
    // used for algorithms 5–32 which have 2+ output carriers.
    function getDX7CarrierModPair(alg) {
      const i = Math.max(0, Math.min(31, alg));
      const hasSecondary = i >= 4; // algorithms 5–32 have ≥2 carriers
      return { ci: 5, mi: 4, ci2: hasSecondary ? 3 : -1, mi2: hasSecondary ? 2 : -1 };
    }

    function parseDX7SysEx(data) {
      const bytes = data instanceof Uint8Array ? data : new Uint8Array(data);
      let voiceData = null;
      if (bytes.length >= 4104 && bytes[0] === 0xF0 && bytes[1] === 0x43 && bytes[3] === 0x09) {
        voiceData = bytes.slice(6, 6 + 4096);
      } else if (bytes.length >= 4096) {
        voiceData = bytes.slice(0, 4096);
      } else { return null; }
      const presets = [];
      for (let v = 0; v < 32; v++) {
        const base = v * 128;
        let name = '';
        for (let i = 118; i < 128; i++) { const c = voiceData[base + i] & 0x7F; name += (c >= 32 && c < 127) ? String.fromCharCode(c) : ' '; }
        name = name.trim() || ('PATCH ' + (v + 1));
        const algorithm = voiceData[base + 110] & 0x1F;
        const ops = [];
        for (let op = 0; op < 6; op++) {
          const ob = base + op * 17;
          ops.push({ egR: [voiceData[ob],voiceData[ob+1],voiceData[ob+2],voiceData[ob+3]], egL: [voiceData[ob+4],voiceData[ob+5],voiceData[ob+6],voiceData[ob+7]], level: voiceData[ob+14]&0x7F, coarse: (voiceData[ob+15]&0x1F)||1 });
        }
        const { ci, mi, ci2, mi2 } = getDX7CarrierModPair(algorithm);
        const car = ops[ci], mod = ops[mi];
        const t = (r, max) => Math.max(0.001, ((99 - Math.max(0, r)) / 99) * max);
        const preset = {
          name,
          harmonicity:     Math.max(0.1, Math.min(20, mod.coarse / car.coarse)),
          modulationIndex: Math.max(0,   Math.min(20, (mod.level / 99) * 20)),
          attack:    t(car.egR[0], 5.0), decay:     t(car.egR[1], 4.0), sustain: car.egL[2]/99, release:    t(car.egR[3], 5.0),
          modAttack: t(mod.egR[0], 5.0), modDecay:  t(mod.egR[1], 4.0), modSustain: mod.egL[2]/99, modRelease: t(mod.egR[3], 5.0),
        };
        // Add second FM layer for multi-carrier algorithms when secondary carrier is audible
        if (ci2 >= 0 && ops[ci2].level >= 20) {
          const car2 = ops[ci2], mod2 = ops[mi2];
          preset.harmonicity2  = Math.max(0.1, Math.min(20, mod2.coarse / car2.coarse));
          preset.modIndex2     = Math.max(0,   Math.min(20, (mod2.level / 99) * 20));
          preset.layer2Mix     = car.level > 0 ? Math.max(0.25, Math.min(0.75, (car2.level / car.level) * 0.65)) : 0.5;
          preset.layer2ModDecayMult = 0.7;
        }
        presets.push(preset);
      }
      return presets;
    }

    // ════════════════════════════════════════════════════
    // DX7 6-OP BANK FETCHING + PARSING (for AudioWorklet engine)
    // Parses real DX7 SysEx into patch objects used by dx7-worklet.js
    // Source tables from mmontag/dx7-synth-js (MIT License)
    // ════════════════════════════════════════════════════

    // Bundled DX7 ROM banks — 7 × 4104-byte SysEx dumps, base64-encoded
    const _DX7_ROM_DATA = {
      'ROM1A': '',
      'ROM1B': '',
      'ROM2A': '',
      'ROM2B': '',
      'Dexed': '',
      'ENO': '',
      'Carlos': '',
      'ROM3A': '',
      'ROM3B': '',
      'ROM4A': '',
      'ROM4B': '',
      'VRC Sustain A': '',
      'VRC Sustain B': '',
      'VRC SFX A': '',
      'VRC SFX B': '',
      'VRC Synth A': '',
      'VRC Synth B': '',
      'Bristow A': '',
      'Bristow B': '',
      'Leuenberger A': '',
      'Leuenberger B': '',
      'Studio 64 A': '',
      'Studio 64 B': '',
      'Bo Tomlyn A': '',
      'Bo Tomlyn B': '',
      'Bo Tomlyn 2A': '',
      'Bo Tomlyn 2B': '',
      'BT Sound EFX A': '',
      'BT Sound EFX B': '',
      'BT Analog A': '',
      'BT Analog B': '',
      'Choir A': '',
      'Choir B': '',
      'Choir C': '',
      'Ether A': '',
      'Ether B': '',
      'Ether C': '',
      'Ether D': '',
      'Godric FX A': '',
      'Godric FX B': '',
      'Godric FX C': '',
      'Synth Sustain A': '',
      'Synth Sustain B': '',
      'Synth Sustain C': '',
      'Female Voices A': '',
      'Female Voices B': '',
      'Male Voices': '',
    };

    function _dx7RomToBytes(name) {
      const b64 = _DX7_ROM_DATA[name];
      if (!b64) return null;
      const bin = atob(b64);
      const bytes = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
      return bytes;
    }

    // Category display order
    const DX7_CATEGORY_ORDER = ['Voice','Crystal','Pad','Strings','FX','Lead','Keys','Brass','Bass','Pluck','Perc','Other'];

    // Keyword → category mapping (checked in priority order; DX7 names are 10 chars max)
    const _DX7_CAT_MAP = [
      // Voices/choirs first — distinct from generic pads
      ['Voice',   ['CHOIR','VOICE','VOX ','HUMAN','AHHS','OOHS','WHISPER','ANGEL','HEAVEN','HALLELUJ','SCAT','BREATH']],
      // Crystal/bell textures — the signature DX7 sound
      ['Crystal', ['CRYSTAL','BELL ','BELLS','GLOCK','CHIME','CHIMES','GLASS','TUBULAR','CELESTE','MUSIC BOX','MUSICBOX','TINE','VIBRAPH','MARIMB','METAL ','STEELDRM','TINKER']],
      // Atmospheric pads and evolving textures
      ['Pad',     ['PAD','ATMOSPH','ATNOS','SWEEP','BLANKET','VELVET','LUSH','WARM ','SYNTH ST','DREAMY','SAWPAD','CLOUD','MIST ','DRIFT','DRONE','FOG ','SHIMMER','FANTASY','WONDER','COSMIC','GALAXY','STARDUST','MYSTICAL','MAGIC ','ETHER','SPACE P']],
      // Orchestral strings (separate from pads)
      ['Strings', ['STRING','STRINGS','STR ','VIOLIN','VIOLA','CELLO','CONTRAB','ORCH ','ENSEMBLE','ENS ']],
      // Electronic FX, noise, sci-fi sounds
      ['FX',      ['FX ','SFX','NOISE','SPACE ','LASER','ZAP ','WIND ','WATER','RAIN ','WHOOSH','STORM','EFFECT','THUNDER','SWEEP ','ROBO','ROBOT','SCI-FI','SCIFI','WARP','PHASE','COMPU','SYNC ','DIGITAL']],
      // Leads / solos
      ['Lead',    ['LEAD','SOLO','SCREAMER','SYNC L']],
      // Keyboard instruments
      ['Keys',    ['PIANO','E.PIANO','E.P.','E-PIANO','CLAV','ORGAN','VIBES','VIBE ','RHODES','HARPSI','ELECTRIC','FM PIANO','DX PIANO']],
      // Brass and winds
      ['Brass',   ['BRASS','TRUMPET','TRMPET','TRPT','TROMBON','TROMB','FRENCH H','HORN ','SAX ','WINDS','WIND ','FLUTE','OBOE','CLARINET']],
      // Bass
      ['Bass',    ['BASS']],
      // Plucked instruments
      ['Pluck',   ['GUITAR','PLUCK','HARP ','BANJO','KOTO','SITAR','LUTE ','PIZZ','MANDOLIN']],
      // Percussion
      ['Perc',    ['PERC','XYLO','TAMB','TIMPAN','SNARE','CONGA','DRUM','TOM ']],
    ];

    function _categorizeDX7(name) {
      const u = (name + ' ').toUpperCase(); // trailing space so "STR " matches end-of-name too
      for (const [cat, kws] of _DX7_CAT_MAP) {
        if (kws.some(k => u.includes(k))) return cat;
      }
      return 'Other';
    }

    // Decode all bundled ROMs synchronously, merge, deduplicate, and categorize
    let _dx7AllPatchesCache = null;

    function fetchAllDX7Patches() {
      if (_dx7AllPatchesCache) return Promise.resolve(_dx7AllPatchesCache);
      const seen = new Set();
      const all = [];
      for (const bankName of Object.keys(_DX7_ROM_DATA)) {
        const bytes = _dx7RomToBytes(bankName);
        if (!bytes) continue;
        const patches = parseDX7BankBytes(bytes);
        if (!patches) continue;
        for (const p of patches) {
          const key = p.name.trim().toUpperCase();
          if (seen.has(key)) continue;
          seen.add(key);
          all.push({ ...p, cat: _categorizeDX7(p.name), bank: bankName });
        }
      }
      all.sort((a, b) => {
        const oa = DX7_CATEGORY_ORDER.indexOf(a.cat), ob = DX7_CATEGORY_ORDER.indexOf(b.cat);
        if (oa !== ob) return oa - ob;
        return a.name.localeCompare(b.name);
      });
      _dx7AllPatchesCache = all;
      return Promise.resolve(all);
    }

    // Legacy alias
    const DX7_BANKS = Object.keys(_DX7_ROM_DATA).map(name => ({ name }));

    const _DX7_OUTPUT_LEVEL_TABLE = [
      0.000000, 0.000337, 0.000476, 0.000674, 0.000952, 0.001235, 0.001602, 0.001905, 0.002265, 0.002694,
      0.003204, 0.003810, 0.004531, 0.005388, 0.006408, 0.007620, 0.008310, 0.009062, 0.010776, 0.011752,
      0.013975, 0.015240, 0.016619, 0.018123, 0.019764, 0.021552, 0.023503, 0.025630, 0.027950, 0.030480,
      0.033238, 0.036247, 0.039527, 0.043105, 0.047006, 0.051261, 0.055900, 0.060960, 0.066477, 0.072494,
      0.079055, 0.086210, 0.094012, 0.102521, 0.111800, 0.121919, 0.132954, 0.144987, 0.158110, 0.172420,
      0.188025, 0.205043, 0.223601, 0.243838, 0.265907, 0.289974, 0.316219, 0.344839, 0.376050, 0.410085,
      0.447201, 0.487676, 0.531815, 0.579948, 0.632438, 0.689679, 0.752100, 0.820171, 0.894403, 0.975353,
      1.063630, 1.159897, 1.264876, 1.379357, 1.504200, 1.640341, 1.788805, 1.950706, 2.127260, 2.319793,
      2.529752, 2.758714, 3.008399, 3.280683, 3.577610, 3.901411, 4.254519, 4.639586, 5.059505, 5.517429,
      6.016799, 6.561366, 7.155220, 7.802823, 8.509039, 9.279172, 10.11901, 11.03486, 12.03360, 13.12273,
    ];

    // Cache: url → patch array
    const _dx7BankCache = {};

    // Parse a 4104-byte DX7 32-voice SysEx Uint8Array into 32 patch objects
    // compatible with dx7-worklet.js's DX7Voice constructor.
    function parseDX7BankBytes(bytes) {
      if (!(bytes instanceof Uint8Array)) bytes = new Uint8Array(bytes);
      // Accept both bare voice data (4096) and full SysEx (4104: F0 43 ?? 09 20 00 ... F7)
      let vd;
      if (bytes.length >= 4104 && bytes[0] === 0xF0 && bytes[1] === 0x43 && bytes[3] === 0x09) {
        vd = bytes.subarray(6, 6 + 4096);
      } else if (bytes.length >= 4096) {
        vd = bytes.subarray(0, 4096);
      } else {
        return null;
      }

      const patches = [];
      for (let v = 0; v < 32; v++) {
        const base = v * 128;
        // ops stored Op6..Op1 in SysEx; we map to operators[0]=Op1..operators[5]=Op6
        const operators = new Array(6);
        for (let i = 5; i >= 0; i--) {
          const ob = base + (5 - i) * 17;
          const freqCoarse = vd[ob + 15] >> 1;
          const freqFine   = vd[ob + 16];
          const oscMode    = vd[ob + 15] & 1;
          const volume     = vd[ob + 14] & 0x7F;
          const detune     = (vd[ob + 12] >> 3) - 7;
          const velSens    = (vd[ob + 13] >> 2) & 7;
          let freqRatio, freqFixed;
          if (oscMode === 0) {
            freqRatio = (freqCoarse || 0.5) * (1 + freqFine / 100);
          } else {
            freqFixed = Math.pow(10, freqCoarse % 4) * (1 + (freqFine / 99) * 8.772);
          }
          operators[i] = {
            rates:       [vd[ob], vd[ob+1], vd[ob+2], vd[ob+3]],
            levels:      [vd[ob+4], vd[ob+5], vd[ob+6], vd[ob+7]],
            velocitySens: velSens,
            oscMode,
            freqCoarse,
            freqFine,
            freqRatio:   freqRatio  || 1.0,
            freqFixed:   freqFixed  || 440,
            detune,
            volume,
            outputLevel: _DX7_OUTPUT_LEVEL_TABLE[Math.min(99, volume)] * 1.27,
            ampL: 0.7071,
            ampR: 0.7071,
          };
        }
        let name = '';
        for (let i = 118; i < 128; i++) {
          const c = vd[base + i] & 0x7F;
          name += (c >= 32 && c < 127) ? String.fromCharCode(c) : ' ';
        }
        name = name.trim() || ('PATCH ' + (v + 1));
        patches.push({
          name,
          algorithm:        (vd[base + 110] & 0x1F) + 1,
          feedback:          vd[base + 111] & 7,
          lfoSpeed:          vd[base + 112],
          lfoDelay:          vd[base + 113],
          lfoPitchModDepth:  vd[base + 114],
          lfoAmpModDepth:    vd[base + 115],
          lfoPitchModSens:   vd[base + 116] >> 4,
          lfoWaveform:      (vd[base + 116] >> 1) & 7,
          operators,
          controllerModVal:  0,
        });
      }
      return patches;
    }

    // Fetch a DX7 bank by URL, returning parsed patch array (cached per URL)
    async function fetchDX7Bank(url) {
      if (_dx7BankCache[url]) return _dx7BankCache[url];
      const resp   = await fetch(url);
      if (!resp.ok) throw new Error('DX7 bank fetch failed: ' + resp.status);
      const buf    = await resp.arrayBuffer();
      const patches = parseDX7BankBytes(new Uint8Array(buf));
      if (!patches) throw new Error('DX7 bank parse failed');
      _dx7BankCache[url] = patches;
      return patches;
    }

    // ════════════════════════════════════════════════════
    // WAVETABLE ENGINE — FFT (Corban Brook, MIT License)
    //                    WaveTable (Google Chrome Labs, BSD License)
    // ════════════════════════════════════════════════════
    function _WT_FourierTransform(bufferSize, sampleRate) {
      this.bufferSize = bufferSize; this.sampleRate = sampleRate;
      this.real = new Float32Array(bufferSize); this.imag = new Float32Array(bufferSize);
    }
    function _WT_FFT(bufferSize, sampleRate) {
      _WT_FourierTransform.call(this, bufferSize, sampleRate);
      this.reverseTable = new Uint32Array(bufferSize);
      var limit = 1, bit = bufferSize >> 1, i;
      while (limit < bufferSize) {
        for (i = 0; i < limit; i++) this.reverseTable[i + limit] = this.reverseTable[i] + bit;
        limit <<= 1; bit >>= 1;
      }
      this.sinTable = new Float32Array(bufferSize);
      this.cosTable = new Float32Array(bufferSize);
      for (i = 0; i < bufferSize; i++) {
        this.sinTable[i] = Math.sin(-Math.PI / i);
        this.cosTable[i] = Math.cos(-Math.PI / i);
      }
    }
    _WT_FFT.prototype.inverse = function(real, imag) {
      var n = this.bufferSize, i;
      real = real || this.real; imag = imag || this.imag;
      var nyquist = imag[0]; imag[0] = 0; real[n>>1] = nyquist; imag[n>>1] = 0;
      for (i = 1 + (n>>1); i < n; i++) { real[i] = real[n-i]; imag[i] = -imag[n-i]; }
      for (i = 0; i < n; i++) imag[i] *= -1;
      var revReal = new Float32Array(n), revImag = new Float32Array(n);
      for (i = 0; i < n; i++) { revReal[i] = real[this.reverseTable[i]]; revImag[i] = imag[this.reverseTable[i]]; }
      real = revReal; imag = revImag;
      var halfSize = 1, off, tr, ti, tmpReal, psr, psi, csr, csi;
      while (halfSize < n) {
        psr = this.cosTable[halfSize]; psi = this.sinTable[halfSize];
        csr = 1; csi = 0;
        for (var fftStep = 0; fftStep < halfSize; fftStep++) {
          i = fftStep;
          while (i < n) {
            off = i + halfSize;
            tr = csr * real[off] - csi * imag[off];
            ti = csr * imag[off] + csi * real[off];
            real[off] = real[i] - tr; imag[off] = imag[i] - ti;
            real[i] += tr; imag[i] += ti;
            i += halfSize << 1;
          }
          tmpReal = csr;
          csr = tmpReal * psr - csi * psi;
          csi = tmpReal * psi + csi * psr;
        }
        halfSize <<= 1;
      }
      var buf = new Float32Array(n);
      for (i = 0; i < n; i++) buf[i] = real[i] / n;
      return buf;
    };

    function _WT_WaveTable(name, audioCtx) {
      this.name = name; this.context = audioCtx; this.sampleRate = audioCtx.sampleRate;
      this.waveTableSize = 4096; this.numberOfResampleRanges = 11; this.buffers = null;
    }
    _WT_WaveTable.prototype.getRateScale = function() { return this.waveTableSize / this.sampleRate; };
    _WT_WaveTable.prototype.getNumberOfPartialsForRange = function(j) {
      var n = Math.pow(2, 1 + this.numberOfResampleRanges - j);
      if (this.sampleRate > 48000) n *= 2; return n;
    };
    _WT_WaveTable.prototype.getWaveDataForPitch = function(pitchFrequency) {
      var nyquist = 0.5 * this.sampleRate;
      var lowestFundamental = nyquist / this.getNumberOfPartialsForRange(0);
      var ratio = pitchFrequency / lowestFundamental;
      var range = ratio === 0 ? 0 : Math.floor(Math.log(ratio) / Math.LN2);
      return this.buffers[Math.max(0, Math.min(this.numberOfResampleRanges - 1, range))];
    };
    _WT_WaveTable.prototype.createBuffers = function() {
      this.buffers = [];
      var f = this.frequencyData, finalScale = 1, n = this.waveTableSize, halfN = n >> 1, i, j;
      for (j = 0; j < this.numberOfResampleRanges; j++) {
        var frame = new _WT_FFT(n, this.sampleRate);
        for (i = 0; i < halfN; i++) { frame.real[i] = n * f.real[i]; frame.imag[i] = n * f.imag[i]; }
        var npartials = this.getNumberOfPartialsForRange(j);
        for (i = npartials + 1; i < halfN; i++) { frame.real[i] = 0; frame.imag[i] = 0; }
        if (npartials < halfN) frame.imag[0] = 0;
        frame.real[0] = 0;
        if (j === 0) {
          var power = 0;
          for (i = 1; i < halfN; i++) { var x = frame.real[i], y = frame.imag[i]; power += x*x + y*y; }
          power = Math.sqrt(power) / n;
          finalScale = power > 0 ? 0.5 / power : 1;
        }
        var data = frame.inverse();
        var abuf = this.context.createBuffer(1, data.length, this.sampleRate);
        var ch = abuf.getChannelData(0);
        for (i = 0; i < data.length; i++) ch[i] = finalScale * data[i];
        this.buffers[j] = abuf;
      }
    };

    // Cache: name → _WT_WaveTable; pending: name → [callbacks]
    const _wtPending = {};
    function _wtLoadWave(name, callback) {
      if (_wtCache[name]) { callback(_wtCache[name]); return; }
      if (_wtPending[name]) { _wtPending[name].push(callback); return; }
      _wtPending[name] = [callback];
      fetch(WT_BASE_URL + encodeURIComponent(name))
        .then(r => r.text())
        .then(txt => {
          const f = eval('(' + txt + ')');
          const ctx = Tone.context.rawContext;
          const wt = new _WT_WaveTable(name, ctx);
          const len = f.real.length;
          wt.frequencyData = { real: new Float32Array(len), imag: new Float32Array(len) };
          for (let i = 0; i < len; i++) { wt.frequencyData.real[i] = f.real[i]; wt.frequencyData.imag[i] = f.imag[i]; }
          wt.createBuffers();
          _wtCache[name] = wt;
          (_wtPending[name] || []).forEach(cb => cb(wt));
          delete _wtPending[name];
        })
        .catch(e => { console.warn('WT load failed:', name, e); delete _wtPending[name]; });
    }

    // ════════════════════════════════════════════════════
    // WAVETABLE PRESETS (Google Chrome Labs wave-tables)
    // ════════════════════════════════════════════════════
    const WT_BASE_URL = 'https://googlechromelabs.github.io/web-audio-samples/demos/wavetable-synth/wave-tables/';
    // Exact filenames as they appear on the Google Chrome Labs server
    const WT_NAMES = [
      '01_Saw','02_Triangle','03_Square','04_Noise','05_Pulse',
      '06_Warm_Saw','07_Warm_Triangle','08_Warm_Square','09_Dropped_Saw','10_Dropped_Square',
      '11_TB303_Square','Bass','Bass_Amp360','Bass_Fuzz','Bass_Fuzz_ 2','Bass_Sub_Dub','Bass_Sub_Dub_2',
      'Brass','Brit_Blues','Brit_Blues_Driven','Buzzy_1','Buzzy_2','Celeste','Chorus_Strings',
      'Dissonant Piano','Dissonant_1','Dissonant_2','Dyna_EP_Bright','Dyna_EP_Med','Ethnic_33',
      'Full_1','Full_2','Guitar_Fuzz','Harsh','Mkl_Hard','Organ_2','Organ_3',
      'Phoneme_ah','Phoneme_bah','Phoneme_ee','Phoneme_o','Phoneme_ooh','Phoneme_pop_ahhhs',
      'Piano','Putney_Wavering','Throaty','Trombone','Twelve String Guitar 1','Twelve_OpTines',
      'Wurlitzer','Wurlitzer_2',
    ];
    // Grouped banks for the wavetable preset picker
    const WT_BANKS = [
      { name: 'Basic',  items: ['01_Saw','02_Triangle','03_Square','04_Noise','05_Pulse','06_Warm_Saw','07_Warm_Triangle','08_Warm_Square','09_Dropped_Saw','10_Dropped_Square','11_TB303_Square'] },
      { name: 'Bass',   items: ['Bass','Bass_Amp360','Bass_Fuzz','Bass_Fuzz_ 2','Bass_Sub_Dub','Bass_Sub_Dub_2'] },
      { name: 'Lead',   items: ['Brass','Brit_Blues','Brit_Blues_Driven','Buzzy_1','Buzzy_2','Harsh','Full_1','Full_2','Mkl_Hard','Trombone'] },
      { name: 'Keys',   items: ['Celeste','Dissonant Piano','Dyna_EP_Bright','Dyna_EP_Med','Piano','Twelve_OpTines','Wurlitzer','Wurlitzer_2'] },
      { name: 'Organ',  items: ['Organ_2','Organ_3','Putney_Wavering'] },
      { name: 'Pad',    items: ['Chorus_Strings'] },
      { name: 'Pluck',  items: ['Ethnic_33','Guitar_Fuzz','Twelve String Guitar 1'] },
      { name: 'Vocal',  items: ['Phoneme_ah','Phoneme_bah','Phoneme_ee','Phoneme_o','Phoneme_ooh','Phoneme_pop_ahhhs','Throaty'] },
      { name: 'FX',     items: ['Dissonant_1','Dissonant_2'] },
    ];
    // Cache for loaded _WT_WaveTable objects keyed by wave name
    const _wtCache = {};

